onClick:
{{
  (async () => {
    // 1. Kiểm tra điều kiện đầu vào
    if (!inp_MaCongCu.text || !inp_SoLuong.text || !sel_NhanVien.selectedOptionValue) {
      showAlert('Vui lòng điền đầy đủ Mã vật liệu, Số lượng và Nhân viên!', 'warning');
      return; // Dừng lại nếu thiếu thông tin
    }

    try {
      // 2. Thực thi lệnh Nhập kho
      await Action_NhapKho.run();

      // 3. Thông báo thành công
      showAlert('Nhập kho thành công! / 入库成功!', 'success');

      // 4. LÀM MỚI TẤT CẢ CÁC BẢNG LIÊN QUAN
      await Get_Bang_Tool.run();         // Load lại bảng danh mục công cụ
      await Get_LS_Nhap.run();           // Load lại lịch sử nhập
      await Get_Inventory_Data.run();    // Lệnh mới thêm: Load lại Bảng kiểm kê

      // 5. Reset lại Form nhập liệu
      resetWidget('Form_Xuat_Nhap_1', true);

    } catch (err) {
      // 6. Xử lý nếu có lỗi xảy ra
      showAlert('Lỗi: ' + err.message, 'error');
    }
  })()
}}
